INSERT INTO `media_file` VALUES (18,_binary '<!DOCTYPE html>\n<html>\n<head>\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1\">\n  <link rel=\"stylesheet\" href=\"https://maxcdn.bootstrapcdn.com/bootstrap/3.3.7/css/bootstrap.min.css\">\n  <script src=\"https://ajax.googleapis.com/ajax/libs/jquery/3.2.1/jquery.min.js\"></script>\n  <script src=\"https://maxcdn.bootstrapcdn.com/bootstrap/3.3.7/js/bootstrap.min.js\"></script>\n\n  <!-- Latest compiled and minified CSS -->\n<link rel=\"stylesheet\" href=\"https://cdnjs.cloudflare.com/ajax/libs/bootstrap-select/1.12.4/css/bootstrap-select.min.css\">\n\n<!-- Latest compiled and minified JavaScript -->\n<script src=\"https://cdnjs.cloudflare.com/ajax/libs/bootstrap-select/1.12.4/js/bootstrap-select.min.js\"></script>\n\n\n\n</head>\n<body>\n    <section id=\"about-us\" class=\"container main\">\n        <div class=\"row-fluid\">\n            <div class=\"span8\" >\n                <div class=\"blog\">\n\n                  <div class=\"blog-item well\">\n                    <a href=\"#\"><h2>Heading2</h2></a>\n                    <select class=\"selectpicker\" multiple id=\"select_county\" data-live-search=\"true\" data-style=\"btn-primary\">\n                      <option>County1</option>\n                      <option>County2</option>\n		                            <option>County1</option>\n                      <option>County2</option>\n                      <option>County1</option>\n                      <option>County2</option>\n                    </select>\n\n                    <select class=\"selectpicker\" id=\"select_event\" data-live-search=\"true\" data-style=\"btn-primary\">\n                      <option>event1</option>\n                      <option>event2</option>\n                    </select>\n\n                    <input type=\"submit\" class=\"btn btn-info\" value=\"Submit Button\">\n\n\n                    </div>\n\n        </div>\n    </div>\n</div>\n      </section>\n\n</body>\n</html>\n',15,2,'mail.html','text/html',0),(19,_binary '<!doctype html>\n<html>\n\n<head>\n  <meta content=\"width=device-width\" name=\"viewport\" />\n  <meta content=\"text/html; charset=UTF-8\" http-equiv=\"Content-Type\" />\n  <title>Simple Transactional Email</title>\n  <style>\n    /* -------------------------------------\n      GLOBAL RESETS\n  ------------------------------------- */\n\n    /*All the styling goes here*/\n\n    img {\n      border: none;\n      -ms-interpolation-mode: bicubic;\n      max-width: 100%;\n    }\n\n    body {\n      background-color: #f6f6f6;\n      font-family: sans-serif;\n      -webkit-font-smoothing: antialiased;\n      font-size: 14px;\n      line-height: 1.4;\n      margin: 0;\n      padding: 0;\n      -ms-text-size-adjust: 100%;\n      -webkit-text-size-adjust: 100%;\n    }\n\n    table {\n      border-collapse: separate;\n      mso-table-lspace: 0pt;\n      mso-table-rspace: 0pt;\n      width: 100%;\n    }\n\n    table td {\n      font-family: sans-serif;\n      font-size: 14px;\n      vertical-align: top;\n    }\n\n    /* -------------------------------------\n      BODY & CONTAINER\n  ------------------------------------- */\n\n    .body {\n      background-color: #f6f6f6;\n      width: 100%;\n    }\n\n    /* Set a max-width, and make it display as block so it will automatically stretch to that width, but will also shrink down on a phone or something */\n    .container {\n      display: block;\n      margin: 0 auto !important;\n      /* makes it centered */\n      max-width: 580px;\n      padding: 10px;\n      width: 580px;\n    }\n\n    /* This should also be a block element, so that it will fill 100% of the .container */\n    .content {\n      box-sizing: border-box;\n      display: block;\n      margin: 0 auto;\n      max-width: 580px;\n      padding: 10px;\n    }\n\n    /* -------------------------------------\n      HEADER, FOOTER, MAIN\n  ------------------------------------- */\n    .main {\n      background: #ffffff;\n      border-radius: 3px;\n      width: 100%;\n    }\n\n    .wrapper {\n      box-sizing: border-box;\n      padding: 20px;\n    }\n\n    .content-block {\n      padding-bottom: 10px;\n      padding-top: 10px;\n    }\n\n    .footer {\n      clear: both;\n      margin-top: 10px;\n      text-align: center;\n      width: 100%;\n    }\n\n    .footer td,\n    .footer p,\n    .footer span,\n    .footer a {\n      color: #999999;\n      font-size: 12px;\n      text-align: center;\n    }\n\n    /* -------------------------------------\n      TYPOGRAPHY\n  ------------------------------------- */\n    h1,\n    h2,\n    h3,\n    h4 {\n      color: #000000;\n      font-family: sans-serif;\n      font-weight: 400;\n      line-height: 1.4;\n      margin: 0;\n      margin-bottom: 30px;\n    }\n\n    h1 {\n      font-size: 35px;\n      font-weight: 300;\n      text-align: center;\n      text-transform: capitalize;\n    }\n\n    p,\n    ul,\n    ol {\n      font-family: sans-serif;\n      font-size: 14px;\n      font-weight: normal;\n      margin: 0;\n      margin-bottom: 15px;\n    }\n\n    p li,\n    ul li,\n    ol li {\n      list-style-position: inside;\n      margin-left: 5px;\n    }\n\n    a {\n      color: #3498db;\n      text-decoration: underline;\n    }\n\n    /* -------------------------------------\n      BUTTONS\n  ------------------------------------- */\n    .btn {\n      box-sizing: border-box;\n      width: 100%;\n    }\n\n    .btn>tbody>tr>td {\n      padding-bottom: 15px;\n    }\n\n    .btn table {\n      width: auto;\n    }\n\n    .btn table td {\n      background-color: #ffffff;\n      border-radius: 5px;\n      text-align: center;\n    }\n\n    .btn a {\n      background-color: #ffffff;\n      border: solid 1px #3498db;\n      border-radius: 5px;\n      box-sizing: border-box;\n      color: #3498db;\n      cursor: pointer;\n      display: inline-block;\n      font-size: 14px;\n      font-weight: bold;\n      margin: 0;\n      padding: 12px 25px;\n      text-decoration: none;\n      text-transform: capitalize;\n    }\n\n    .btn-primary table td {\n      background-color: #3498db;\n    }\n\n    .btn-primary a {\n      background-color: #3498db;\n      border-color: #3498db;\n      color: #ffffff;\n    }\n\n    /* -------------------------------------\n      OTHER STYLES THAT MIGHT BE USEFUL\n  ------------------------------------- */\n    .last {\n      margin-bottom: 0;\n    }\n\n    .first {\n      margin-top: 0;\n    }\n\n    .align-center {\n      text-align: center;\n    }\n\n    .align-right {\n      text-align: right;\n    }\n\n    .align-left {\n      text-align: left;\n    }\n\n    .clear {\n      clear: both;\n    }\n\n    .mt0 {\n      margin-top: 0;\n    }\n\n    .mb0 {\n      margin-bottom: 0;\n    }\n\n    .preheader {\n      color: transparent;\n      display: none;\n      height: 0;\n      max-height: 0;\n      max-width: 0;\n      opacity: 0;\n      overflow: hidden;\n      mso-hide: all;\n      visibility: hidden;\n      width: 0;\n    }\n\n    .powered-by a {\n      text-decoration: none;\n    }\n\n    hr {\n      border: 0;\n      border-bottom: 1px solid #f6f6f6;\n      margin: 20px 0;\n    }\n\n    /* -------------------------------------\n      RESPONSIVE AND MOBILE FRIENDLY STYLES\n  ------------------------------------- */\n    @media only screen and (max-width: 620px) {\n      table[class=body] h1 {\n        font-size: 28px !important;\n        margin-bottom: 10px !important;\n      }\n\n      table[class=body] p,\n      table[class=body] ul,\n      table[class=body] ol,\n      table[class=body] td,\n      table[class=body] span,\n      table[class=body] a {\n        font-size: 16px !important;\n      }\n\n      table[class=body] .wrapper,\n      table[class=body] .article {\n        padding: 10px !important;\n      }\n\n      table[class=body] .content {\n        padding: 0 !important;\n      }\n\n      table[class=body] .container {\n        padding: 0 !important;\n        width: 100% 